INSERT INTO `jinengxuqiu` (`addtime`, `xuqiubianhao`, `xuqiubiaoti`, `jinengfenlei`, `fengmian`, `fabushijian`, `xuqiufeiyong`, `xuqiumiaoshu`, `xuqiuxiangqing`, `yonghuzhanghao`, `yonghuxingming`, `shoujihao`, `xinyuzhishu`, `leixing`, `sfsh`, `shhf`, `thumbsupnum`, `crazilynum`, `clicktime`, `clicknum`, `discussnum`, `totalscore`, `storeupnum`) VALUES
('2026-04-27 10:00:00','JN20260427005','英语四六级辅导','学习','upload/jinengxuqiu_Python编程入门1.jpg','2026-04-27',60,'英语专业大三，四级620分六级580分，有丰富的辅导经验','<p>英语专业大三学生，成绩优异：</p><ul><li>四级620分、六级580分</li><li>精通听力、阅读、写作、翻译各模块</li><li>总结了一套高效的备考方法</li></ul><p>可以提供一对一辅导，帮助制定复习计划。</p>','zhangqiang','张强','13987654210',90,'技能','待审核','',0,0,NULL,0,0,0,0),
('2026-04-27 11:00:00','JN20260427006','瑜伽入门教学','生活','upload/jinengxuqiu_吉他弹唱教学1.jpg','2026-04-27',45,'练习瑜伽两年，取得了瑜伽教练初级证书','<p>瑜伽爱好者，持有初级教练证书：</p><ul><li>基础体式教学</li><li>呼吸法与冥想指导</li><li>柔韧性训练</li><li>减压放松课程</li></ul><p>适合零基础入门，每次课程约60分钟。</p>','lina','李娜','15187653241',78,'技能','待审核','',0,0,NULL,0,0,0,0),
('2026-04-27 12:00:00','JN20260427007','视频剪辑教学','设计','upload/jinengxuqiu_海报设计教学1.jpg','2026-04-27',70,'熟练使用PR、AE等视频剪辑软件，有多个作品','<p>数字媒体专业学生，擅长视频制作：</p><ul><li>Premiere Pro基础操作</li><li>视频转场与特效</li><li>调色与音频处理</li><li>短视频创作技巧</li></ul><p>可以从零开始教学，也可以帮忙剪辑视频作品。</p>','wufang','吴芳','15065437821',92,'技能','待审核','',0,0,NULL,0,0,0,0);
